import{_ as i,c as t,a1 as c,o as h}from"./chunks/framework.BDxlaA_J.js";const l=JSON.parse('{"title":"Session Hijacking (Chỉnh sửa phiên)","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/10-session-hijacking/0-Introduction.md","filePath":"vi/categories/ethical-hacking-labs/10-session-hijacking/0-Introduction.md"}'),a={name:"vi/categories/ethical-hacking-labs/10-session-hijacking/0-Introduction.md"};function e(s,n,o,r,g,p){return h(),t("div",null,n[0]||(n[0]=[c('<h1 id="session-hijacking-chinh-sua-phien" tabindex="-1">Session Hijacking (Chỉnh sửa phiên) <a class="header-anchor" href="#session-hijacking-chinh-sua-phien" aria-label="Permalink to &quot;Session Hijacking (Chỉnh sửa phiên)&quot;">​</a></h1><p>Tấn công Session Hijacking bao gồm việc khai thác cơ chế kiểm soát phiên web, thường được quản lý bởi một session token.</p><p align="center"><img width="50%" src="https://www.greycampus.com/ckeditor_assets/pictures/231/content_ses.hij.intro.bmp"></p><p>Vì giao thức HTTP sử dụng nhiều kết nối TCP khác nhau, máy chủ web cần một phương pháp để nhận diện từng kết nối của người dùng. Phương pháp phổ biến nhất dựa vào một token mà máy chủ Web gửi đến trình duyệt của client sau khi xác thực thành công. Session token thường bao gồm một chuỗi có độ dài biến đổi và có thể được sử dụng theo nhiều cách khác nhau, như trong URL, trong header của yêu cầu HTTP dưới dạng cookie, trong các phần khác của header yêu cầu HTTP, hoặc trong phần body của yêu cầu HTTP.</p><p>Tấn công Session Hijacking xâm phạm session token bằng cách đánh cắp hoặc dự đoán một session token hợp lệ để truy cập trái phép vào máy chủ Web.</p><p>Session token có thể bị xâm phạm theo nhiều cách khác nhau; phổ biến nhất là:</p><ul><li>Session token có thể dự đoán được</li><li>Session Sniffing (chụp gói tin phiên)</li><li>Tấn công phía client (XSS, mã JavaScript độc hại, Trojan, v.v.)</li><li>Tấn công Man-in-the-middle (trung gian)</li><li>Tấn công Man-in-the-browser (trình duyệt trung gian)</li></ul><p>Nguồn: <a href="https://owasp.org/www-community/attacks/Session_hijacking_attack" target="_blank" rel="noreferrer">https://owasp.org/www-community/attacks/Session_hijacking_attack</a></p>',8)]))}const u=i(a,[["render",e]]);export{l as __pageData,u as default};
